// Cache por dexId: getDexAnimMeta é chamado ~centenas de vezes/frame (por pokemon visível
// × cada slice de animação requisitado). Máximo 151 Gen-1, cache pequeno e estável.
const _dexMetaCache = new Map();
export function getDexAnimMeta(dexId) {
  const dex = Math.max(1, Math.min(151, Number(dexId) || 1));
  const cached = _dexMetaCache.get(dex);
  if (cached !== undefined) return cached;
  const key = String(dex).padStart(3, '0');
  const meta = PMD_ANIM_METADATA[key] || null;
  _dexMetaCache.set(dex, meta);
  return meta;
}

/** @param {'idle'|'walk'|'dig'|'hurt'|'sleep'|'faint'|'charge'|'shoot'|'attack'} kind */
export function getDexAnimSlice(dexId, kind) {
  const m = getDexAnimMeta(dexId);
  if (!m) return null;
  if (kind === 'dig') return m.dig ?? m.walk ?? null;
  if (kind === 'hurt') return m.hurt ?? m.idle ?? null;
  if (kind === 'sleep') return m.sleep ?? m.idle ?? null;
  if (kind === 'faint') return m.faint ?? m.idle ?? null;
  if (kind === 'charge') return m.charge ?? null;
  if (kind === 'shoot') return m.shoot ?? null;
  /** LMB melee: dedicated `attack` in data, else shoot/charge/walk (every species has walk). */
  if (kind === 'attack') return m.attack ?? m.shoot ?? m.charge ?? m.walk ?? m.idle ?? null;
  return m[kind] ?? null;
}
